/** Parser for Assignment 2 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token t = in.readToken();
    if (t != null) throw new ParseException("Expected EOF, found " + t);
    return result;
  }

  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF) {
      return parseIf();
    } else if (t == Lexer.LET) {
      return parseLet();
    } else if (t == Lexer.MAP) {
      return parseMap();
    } else {
      return parseBinaryExp();
    }
  }

  private AST parseIf() {
    consume(Lexer.IF);
    AST test = parseExp();
    consume(Lexer.THEN);
    AST conseq = parseExp();
    consume(Lexer.ELSE);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  private AST parseLet() {
    consume(Lexer.LET);
    List<Def> defs = new ArrayList<>();
    defs.add(parseDef());
    while (in.peek() instanceof Variable) {
      defs.add(parseDef());
    }
    consume(Lexer.IN);
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable)) throw new ParseException("Expected variable, found " + t);
    Variable lhs = (Variable)t;
    consume(Lexer.BIND);
    AST rhs = parseExp();
    consume(SemiColon.ONLY);
    return new Def(lhs, rhs);
  }

  private AST parseMap() {
    consume(Lexer.MAP);
    Variable[] vars = parseIdList();
    consume(Lexer.TO);
    AST body = parseExp();
    return new Map(vars, body);
  }

  private Variable[] parseIdList() {
    if (in.peek() == Lexer.TO) return new Variable[0];
    return parsePropIdList();
  }

  private Variable[] parsePropIdList() {
    List<Variable> vars = new ArrayList<>();
    Token t = in.readToken();
    if (!(t instanceof Variable)) throw new ParseException("Expected variable, found " + t);
    vars.add((Variable)t);
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      t = in.readToken();
      if (!(t instanceof Variable)) throw new ParseException("Expected variable, found " + t);
      vars.add((Variable)t);
    }
    return vars.toArray(new Variable[0]);
  }

  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (true) {
      Token t = in.peek();
      if (t instanceof OpToken && ((OpToken)t).isBinOp()) {
        in.readToken(); // consume
        AST right = parseTerm();
        left = new BinOpApp(((OpToken)t).toBinOp(), left, right);
      } else {
        break;
      }
    }
    return left;
  }

  private AST parseTerm() {
    Token t = in.peek();
    if (t instanceof OpToken && ((OpToken)t).isUnOp()) {
      in.readToken();
      AST arg = parseTerm();
      return new UnOpApp(((OpToken)t).toUnOp(), arg);
    }
    if (t == EmptyConstant.ONLY) {
      in.readToken();
      return EmptyConstant.ONLY;
    }
    if (t instanceof IntConstant) {
      in.readToken();
      return (IntConstant)t;
    }
    if (t instanceof BoolConstant) {
      in.readToken();
      return (BoolConstant)t;
    }

    AST factor = parseFactor();
    // Peek for application
    if (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      consume(RightParen.ONLY);
      return new App(factor, args);
    }
    return factor;
  }

  private AST parseFactor() {
    Token t = in.readToken();
    if (t == LeftParen.ONLY) {
      AST exp = parseExp();
      consume(RightParen.ONLY);
      return exp;
    }
    if (t instanceof PrimFun) {
      return (PrimFun)t;
    }
    if (t instanceof Variable) {
      return (Variable)t;
    }
    if (t == null) throw new ParseException("Unexpected EOF");
    throw new ParseException("Unexpected token: " + t);
  }

  private AST[] parseExpList() {
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];
    }
    return parsePropExpList();
  }

  private AST[] parsePropExpList() {
    List<AST> exps = new ArrayList<>();
    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      exps.add(parseExp());
    }
    return exps.toArray(new AST[0]);
  }

  private void consume(Token expected) {
    Token t = in.readToken();
    if (t != expected) throw new ParseException("Expected " + expected + ", found " + t);
  }

}

