  public void testBinaryAssociativity() {
    checkString("assoc", "((1 + 2) + 3)", "1 + 2 + 3");
    checkString("same precedence", "((1 + 2) * 3)", "1 + 2 * 3");
    checkString("same precedence 2", "((1 * 2) + 3)", "1 * 2 + 3");
  }

  public void testUnary() {
    checkString("unary plus", "+ 1", "+1");
    checkString("unary minus", "- 1", "-1");
    checkString("unary tilde", "~ true", "~true");
    checkString("unary nested", "+ (~ 1)", "+ ~ 1");
    checkString("unary in binop", "(1 + (- 2))", "1 + -2");
  }

  public void testIf() {
    checkString("if", "if true then 1 else 0", "if true then 1 else 0");
    checkString("nested if", "if true then if false then 1 else 2 else 0", "if true then if false then 1 else 2 else 0");
    checkString("if in else", "if true then 1 else (2 + 3)", "if true then 1 else 2 + 3");
  }

  public void testLet() {
    checkString("let", "let x := 1; in x", "let x := 1; in x");
    checkString("let multi", "let x := 1; y := 2; in (x + y)", "let x := 1; y := 2; in x + y");
    checkString("let recursive", "let x := (let y := 1; in y); in x", "let x := let y := 1; in y; in x");
  }

  public void testMap() {
    checkString("map", "map x to x", "map x to x");
    checkString("map multi", "map x,y to (x + y)", "map x, y to x + y");
    checkString("map empty", "map  to 1", "map to 1");
  }

  public void testApp() {
    checkString("app 0", "f()", "f()");
    checkString("app 1", "f(1)", "f(1)");
    checkString("app 2", "f(1, 2)", "f(1, 2)");
    checkString("curried", "(f(1))(2)", "(f(1))(2)");
    checkString("prim app", "first(x)", "first(x)");
    checkString("paren app", "(map x to x)(1)", "(map x to x)(1)");
  }

  public void testComplex() {
    checkString("complex 1", "((x + y) * (if true then 1 else (2 - 3)))", "(x + y) * if true then 1 else 2 - 3");
  }

  public void testErrors() {
    checkError("missing semi", "let x := 1 in x");
    checkError("missing then", "if true 1 else 0");
    checkError("missing in", "let x := 1; x");
    checkError("unmatched paren", "(1 + 2");
    checkError("extra token", "1 + 2 3");
    checkError("illegal char", "1 @ 2");
  }
}

