  if (in.peek() == LeftParen.ONLY) {
    in.readToken(); // consume '('
    AST[] args = parseExpList();
    consume(RightParen.ONLY);
    return new App(factor, args);
  }
  return factor;
}

private AST parseFactor() {
  Token t = in.readToken();
  if (t == LeftParen.ONLY) {
    AST exp = parseExp();
    consume(RightParen.ONLY);
    return exp;
  }
  if (t instanceof PrimFun) {
    return (PrimFun)t;
  }
  if (t instanceof Variable) {
    return (Variable)t;
  }
  if (t == null) throw new ParseException("Unexpected EOF");
  throw new ParseException("Unexpected token: " + t);
}

private AST[] parseExpList() {
  if (in.peek() == RightParen.ONLY) {
    return new AST[0];
  }
  return parsePropExpList();
}

private AST[] parsePropExpList() {
  List<AST> exps = new ArrayList<>();
  exps.add(parseExp());
  while (in.peek() == Comma.ONLY) {
    in.readToken();
    exps.add(parseExp());
  }
  return exps.toArray(new AST[0]);
}

private void consume(Token expected) {
  Token t = in.readToken();
  if (t != expected) throw new ParseException("Expected " + expected + ", found " + t);
}
